define("local_consentmanager/iframe_unlock",["core/ajax","core/notification","core/pending"],function(Ajax,Notification,Pending){"use strict";

function init(){
    document.addEventListener("click",async function(e){
        const btn=e.target.closest(".consentmanager-unlock-iframe");
        if(!btn)return;
        const catid=parseInt(btn.dataset.catid,10),src=btn.dataset.src;
        if(!catid||!src)return;
        const placeholder=btn.closest(".local-consentmanager-placeholder");
        if(!placeholder)return;
        const pending=new Pending("local_consentmanager/iframe_unlock/click");
        btn.disabled=true;
        try{
            const calls=Ajax.call([{methodname:"local_consentmanager_set_consent",args:{catids:[catid],acceptall:false}}]);
            const result=await calls[0];
            if(!result.success){Notification.alert("",result.message);btn.disabled=false;pending.resolve();return;}
            const iframe=document.createElement("iframe");
            iframe.src=src;iframe.width="100%";iframe.height=placeholder.offsetHeight||315;
            iframe.style.border="none";iframe.allow="autoplay; encrypted-media; picture-in-picture";
            iframe.allowFullscreen=true;iframe.loading="lazy";
            placeholder.replaceWith(iframe);
        }catch(err){Notification.exception(err);btn.disabled=false;}finally{pending.resolve();}
    });
}

return{init};
});
